// Priority Queue implementation for Dijkstra's algorithm
type State struct {
	node       int
	heavyCount int // Number of heavy edges used so far
	dist       int // Distance (can be used for general shortest path, but here we only care about reachability)
}

type PriorityQueue []State

func (pq PriorityQueue) Len() int { return len(pq) }

// Min-Heap based on heavyCount first, then distance (though distance isn't strictly necessary for reachability check)
// For this problem, we are essentially checking reachability with a constraint, so minimizing heavyCount is key.
func (pq PriorityQueue) Less(i, j int) bool {
	if pq[i].heavyCount != pq[j].heavyCount {
		return pq[i].heavyCount < pq[j].heavyCount
	}
	return pq[i].dist < pq[j].dist
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(State)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

// canReach checks if there is a path from source to target using at most k heavy edges
// given a specific threshold.
func canReach(n int, adj [][]Edge, source, target int, k int, threshold int) bool {
	// dist[node][heavy_count] stores the minimum number of edges (or just reachability) 
	// to reach 'node' using exactly 'heavy_count' heavy edges.
	// Since we only care about reachability, we can use a boolean array or track the minimum 'heavyCount' 
	// needed to reach a node, but given the constraint k, a 2D DP/BFS/Dijkstra is appropriate.

	// dp[i][j]: Is it possible to reach node i using exactly j heavy edges?
	// Since we are checking for *existence*, a simple BFS structure is sufficient if we manage the state (node, heavy_count).

	// visited[node][heavy_count] = true if this state has been reached.
	visited := make([][]bool, n)
	for i := range visited {
		visited[i] = make([]bool, k+1)
	}

	// Queue for BFS: {node, heavy_count}
	type QueueItem struct {
		node int
		heavyCount int
	}
	queue := []QueueItem{{source, 0}}
	visited[source][0] = true

	for len(queue) > 0 {
		current := queue[0]
		queue = queue[1:]

		u := current.node
		hc := current.heavyCount

		if u == target {
			return true // Found a path to target within constraints
		}

		for _, edge := range adj[u] {
			v := edge.to
			weight := edge.weight

			isHeavy := weight > threshold
			newHC := hc
			if isHeavy {
				newHC++
			}

			if newHC <= k && !visited[v][newHC] {
				visited[v][newHC] = true
				queue = append(queue, QueueItem{v, newHC})
			}
		}
	}

	return false
}

