	to     int
	weight int
}

func solve(n int64, edges [][]int64, source int64, target int64, k int64) int64 {
	nInt := int(n)
	sourceInt := int(source)
	targetInt := int(target)
	kInt := int(k)

	if sourceInt == targetInt {
		return 0
	}

	// 1. Collect all unique edge weights to form the search space for the threshold.
	weights := make(map[int64]bool)
	for _, edge := range edges {
		w := edge[2]
		weights[w] = true
	}

	// The search space for the threshold T is:
	// - T = -1 (conceptually, or 0 if we assume weights are >= 1, but weights are >= 1)
	// - T = all unique edge weights w_i
	// - T = w_i - 1 (the smallest value that changes the classification of w_i)

	// We test thresholds in the set {0} U {w | w is an edge weight} U {w-1 | w is an edge weight and w > 0}.
	// Since weights are >= 1, testing T=0 covers the case where all edges might be heavy (if threshold is 0).

	thresholdCandidates := make(map[int64]bool)
	thresholdCandidates[0] = true // Minimum possible threshold
	for _, edge := range edges {
		w := edge[2]
		thresholdCandidates[w] = true
		if w > 0 {
			thresholdCandidates[w-1] = true
		}
	}

	var sortedCandidates []int64
	for t := range thresholdCandidates {
		sortedCandidates = append(sortedCandidates, t)
	}
	sort.Slice(sortedCandidates, func(i, j int) bool {
		return sortedCandidates[i] < sortedCandidates[j]
	})

	// 2. Check reachability for each candidate threshold using Binary Search or linear scan.
	// Since the property (canReach) is monotonic (if it's true for T, it's true for T' > T), 
	// we can use Binary Search over the sorted unique candidates.

	// The range for BS should be over the sorted unique values of T we generated.

	bestThreshold := int64(-1)
	low := 0
	high := len(sortedCandidates) - 1

	for low <= high {
		midIdx := low + (high-low)/2
		T := sortedCandidates[midIdx]

		// Build adjacency list for the current threshold T
		adj := make([][]Edge, nInt)
		for _, edge := range edges {
			u := int(edge[0])
			v := int(edge[1])
			w := int(edge[2])

			adj[u] = append(adj[u], Edge{to: v, weight: w})
			adj[v] = append(adj[v], Edge{to: u, weight: w})
		}

		if canReach(nInt, adj, sourceInt, targetInt, kInt, int(T)) {
			// T works, try smaller T
			bestThreshold = T
			high = midIdx - 1
		} else {
			// T does not work, need larger T
			low = midIdx + 1
		}
	}

	return bestThreshold
}
