// State for Dijkstra's-like search
type State struct {
	node   int64 // Current node
	cost   int64 // Number of heavy edges used so far
	weight int64 // Not strictly used in this simplified path finding, but good practice for state tracking
}

// Priority Queue implementation for Dijkstra's (min-heap based on 'cost')
type PriorityQueue []State

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	// We want the minimum cost (minimum heavy edges) first
	return pq[i].cost < pq[j].cost
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(State)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

// canReach checks if target is reachable from source using at most k heavy edges,
// given a specific threshold.
func canReach(n int64, adj map[int64]map[int64]int64, source, target, k int64, threshold int64) bool {
	if source == target {
		return true
	}

	// dist[node][heavy_edges_used] stores the minimum "distance" (here, just reachability, but we use a boolean/value)
	// Since we are only concerned about reachability given the constraint k, we use a visited array that tracks
	// the minimum number of heavy edges needed to reach a node.
	// dist[node] = minimum heavy edges to reach 'node'. Initialize to k+1 (infinity for our constraint).
	dist := make([]int64, n)
	for i := int64(0); i < n; i++ {
		dist[i] = k + 1
	}

	// Min-Heap: prioritized by the number of heavy edges used.
	pq := make(PriorityQueue, 0)
	heap.Init(&pq)

	dist[source] = 0
	heap.Push(&pq, State{node: source, cost: 0, weight: 0})

	for pq.Len() > 0 {
		currentState := heap.Pop(&pq).(State)
		u := currentState.node
		currentCost := currentState.cost

		if currentCost > dist[u] {
			continue
		}

		if u == target {
			return true
		}

		// Iterate over neighbors
		for v, originalWeight := range adj[u] {
			// Determine if the edge (u, v) is heavy based on threshold
			isHeavy := originalWeight > threshold
			newCost := currentCost
			if isHeavy {
				newCost++
			}

			if newCost <= k {
				// If we found a path to v with fewer or equal heavy edges than previously recorded
				if newCost < dist[v] {
					dist[v] = newCost
					heap.Push(&pq, State{node: v, cost: newCost, weight: originalWeight})
				}
			}
		}
	}

	return dist[target] <= k
}

// solve finds the minimum threshold such that a valid path exists.
func solve(n int64, edges [][]int64, source int64, target int64, k int64) int64 {
	if source == target {
		return 0
	}

	// 1. Collect all unique edge weights to define the search space for the threshold.
	weightsMap := make(map[int64]bool)
	for _, edge := range edges {
		weightsMap[edge[2]] = true
	}

	// The possible thresholds are:
	// a) 0 (if all weights are positive, 0 ensures all are heavy/light depending on interpretation, but 0 is a valid minimum)
	// b) All existing edge weights w_i.
	// c) w_i - 1 (if we test thresholds just below an existing weight).
	// Since the definition is: <= threshold is light, > threshold is heavy.
	// If we test threshold T, an edge of weight W:
	// W <= T => Light
	// W > T => Heavy
	// The critical points for T are W and W-1 for all weights W.

	var candidateThresholds []int64
	candidateThresholds = append(candidateThresholds, 0) // Smallest possible threshold

	for w := range weightsMap {
		candidateThresholds = append(candidateThresholds, w)
		if w > 0 {
			candidateThresholds = append(candidateThresholds, w-1)
		}
	}

	// Sort and unique the candidate thresholds
	sort.Slice(candidateThresholds, func(i, j int) bool {
		return candidateThresholds[i] < candidateThresholds[j]
	})

	uniqueCandidates := []int64{}
	if len(candidateThresholds) > 0 {
		uniqueCandidates = append(uniqueCandidates, candidateThresholds[0])
		for i := 1; i < len(candidateThresholds); i++ {
			if candidateThresholds[i] > candidateThresholds[i-1] {
				uniqueCandidates = append(uniqueCandidates, candidateThresholds[i])
			}
		}
	}

