	// --- Check function: Can we reach target from source with at most k heavy edges given a threshold T? ---
	check := func(T int64) bool {
		// State in DP/BFS: dp[i][j] = true if node i is reachable using exactly j heavy edges.
		// Since we want AT MOST k, we need to check reachability up to k.

		// dist[i][j]: Minimum weight/cost to reach node i using exactly j heavy edges.
		// However, since we only care about reachability (not shortest path in terms of total weight),
		// a simple boolean reachability matrix/set is enough for a BFS/DFS approach.

		// dp[node][heavy_count] = true if reachable
		dp := make([][]bool, n)
		for i := range dp {
			dp[i] = make([]bool, k+1)
		}

		// Queue for BFS: stores {node, heavy_count}
		queue := []State{{node: source, heavyUsed: 0}}
		dp[source][0] = true

		head := 0
		for head < len(queue) {
			curr := queue[head]
			head++

			if curr.node == target {
				return true // Target reached with <= k heavy edges
			}

			// Iterate over all edges
			for _, edge := range edges {
				u, v, w := edge[0], edge[1], edge[2]

				var nextNode, otherNode int64
				var isHeavy bool

				if u == curr.node {
					nextNode = v
					otherNode = u
				} else if v == curr.node {
					nextNode = u
					otherNode = v
				} else {
					continue // Not incident to current node
				}

				// Determine if this edge is heavy based on threshold T
				if w > T {
					isHeavy = true
				} else {
					isHeavy = false
				}

				nextHeavyUsed := curr.heavyUsed
				if isHeavy {
					nextHeavyUsed++
				}

				if nextHeavyUsed <= k {
					if !dp[nextNode][nextHeavyUsed] {
						dp[nextNode][nextHeavyUsed] = true
						queue = append(queue, State{node: nextNode, heavyUsed: nextHeavyUsed})
					}
				}
			}
		}

		// Check all states for target reachability
		for j := int64(0); j <= k; j++ {
			if dp[target][j] {
				return true
			}
		}
		return false
	}

	// Binary search over the sorted unique weights (potential thresholds)
	// The search space is [0, max_weight_in_edges].

	// We need to check thresholds: 0, and all edge weights w_i.
	// If threshold = w_i - 1, all edges with weight w_i are heavy.
	// If threshold = w_i, all edges with weight w_i are light.

	// Since we are looking for the MINIMUM threshold, we test T = w_i.
	// If check(w_i) is true, w_i is a candidate, and we try smaller.
	// If check(w_i) is false, w_i is too small (or we need a larger threshold to make more edges light), so we try larger.

	low := 0
	high := len(sortedWeights) - 1
	minThreshold := int64(-1)

	for low <= high {
		midIdx := low + (high-low)/2
		T := sortedWeights[midIdx]

		if check(T) {
			// T works, this is a potential minimum. Try smaller thresholds.
			minThreshold = T
			high = midIdx - 1
		} else {
			// T is too small, need a larger threshold to potentially make more edges light.
			low = midIdx + 1
		}
	}

	// Edge case: If we couldn't find any threshold in the set, we must check if the maximum possible threshold works.
	// The largest weight in the graph, W_max, means all edges are light. If check(W_max) is false, no path exists.
	if minThreshold == -1 {
		// If the loop finished without finding a solution, it means even the largest tested threshold failed,
		// or no path exists regardless of threshold (e.g., disconnected graph).
		// The check function handles reachability, so if it returns false even for the largest W_i,
		// the answer is -1, UNLESS the only possible solution is a threshold larger than max(W_i), which is impossible
		// since all edges would be light then.

		// If the graph is disconnected, check(MaxWeight) will be false.

		// We need to ensure that if *any* path exists (even if it requires k+1 heavy edges at low thresholds),
		// the binary search covers the case where the path only exists for T >= W_max.
		// Since all weights are in sortedWeights, and we included 0, the binary search covers all necessary checks.

		// If minThreshold is still -1, it means check(T) was false for all T in sortedWeights.
		// Since sortedWeights includes the max weight, if check(max_weight) is false, no path exists.
		return -1
	}

	return minThreshold
}
